DECLARE
    @today := today(),
    @start := interval_start(@today),
    @end := interval_end(@today)
    SELECT @today = interval(@start, @end)

DECLARE
    @ts := timestamp,
    @bid_price := bid_px_00,
    @bid_size := bid_sz_00,
    @avg_time_range := '5',
    @updates_period := '100',
    @volume_2sec := '2'
SELECT
    @ts,
    @bid_price,
    AVG(@bid_price) OVER (
        ORDER BY @ts
        RANGE BETWEEN @avg_time_range MINUTE PRECEDING AND CURRENT ROW
    ) AS avg_5min,
    COUNT(*) OVER (
        ORDER BY @ts
        RANGE BETWEEN @updates_period MILLISECOND PRECEDING AND CURRENT ROW
    ) AS updates_100ms,
    SUM(@bid_size) OVER (
        ORDER BY @ts
        RANGE BETWEEN @volume_2sec SECOND PRECEDING AND CURRENT ROW
    ) AS volume_2sec
FROM AAPL_orderbook
WHERE @bid_price > 0
LIMIT 10;

DECLARE
    @partition_col := bid_px_00,
    @order_col := timestamp
SELECT
    @order_col,
    @partition_col,
    ROW_NUMBER() OVER (
        PARTITION BY @partition_col
        ORDER BY @order_col
    ) AS row_num
FROM AAPL_orderbook
LIMIT 5;
